cat <<'EOF' > /tmp/test_stackalloc_nint.cs
using System;

var span = (stackalloc nint[4]);
span[0] = 10;
span[1] = 20;
span[2] = 30;
span[3] = 40;

Console.WriteLine($"Length: {span.Length}");
for (int i = 0; i < span.Length; i++)
    Console.WriteLine($"  span[{i}] = {span[i]}");

Console.WriteLine($"Element size: {sizeof(nint)} bytes (native int)");
Console.WriteLine($"nuint test:");
Span<nuint> span2 = stackalloc nuint[2];
span2[0] = 100;
span2[1] = 200;
Console.WriteLine($"  span2[0] = {span2[0]}, span2[1] = {span2[1]}");
EOF
dotnet-script /tmp/test_stackalloc_nint.cs 2>&1 || dotnet run --project /tmp/test_stackalloc_nint.cs 2>&1

